// SPDX-License-Identifier: MIT
pragma solidity ^0.8.19;

import "@openzeppelin/contracts/security/ReentrancyGuard.sol";

uint8 constant PROXY_PALLET = 16;
uint8 constant PROXY_CALL_PROXY = 0;
uint8 constant BALANCES_PALLET = 5;
uint8 constant TRANSFER_ALL_CALL_INDEX = 4;
uint8 constant PROXY_TYPE_TRANSFER = 0;

address constant ISUBTENSOR_BALANCE_TRANSFER_ADDRESS = 0x0000000000000000000000000000000000000800;
address constant IADDRESS_MAPPING_ADDRESS = 0x000000000000000000000000000000000000080C;
address constant IDISPATCH_ADDRESS = 0x0000000000000000000000000000000000000006;

library SubtensorProxyEncoder {
    /// MultiAddress::Id(accountId32)
    function multiAddressId(bytes32 accountId) internal pure returns (bytes memory) {
        return abi.encodePacked(bytes1(0x00), accountId);
    }
    /// Balances.transfer_all { dest, keep_alive }
  function encodeTransferAll(
        bytes32 destAccountId,
        bool keepAlive
    ) internal pure returns (bytes memory) {
        return abi.encodePacked(
            BALANCES_PALLET,
            TRANSFER_ALL_CALL_INDEX,
            multiAddressId(destAccountId),
            keepAlive ? bytes1(0x01) : bytes1(0x00)
        );
    }
    /// Option<ProxyType>: None | Some(type)
    function encodeForceProxyType(bool useForce, uint8 proxyType) internal pure returns (bytes memory) {
        if (!useForce) return hex"00";
        return abi.encodePacked(bytes1(0x01), proxyType);
    }
    /// RuntimeCall::Proxy::proxy { real: delegator, force_proxy_type, call }
    /// @param delegatorId  real account (owner / delegator) — NOT the delegate
    function encodeProxyProxyCall(
        bytes32 delegatorId,
        bool forceTransferType,
        uint8 forcedProxyType,
        bytes memory innerRuntimeCall
    ) internal pure returns (bytes memory) {
        return abi.encodePacked(
            PROXY_PALLET,
            PROXY_CALL_PROXY,
            multiAddressId(delegatorId),
            encodeForceProxyType(forceTransferType, forcedProxyType),
            innerRuntimeCall
        );
    }

    /// @dev Proxy.proxy(real, Some(Transfer)) + Balances.transfer_all(dest, keepAlive) in one pack.
    function encodeProxyTransferAll(
        bytes32 realAccountId,
        bytes32 transferDestAccountId,
        uint8 forcedProxyType,
        bool keepAlive
    ) internal pure returns (bytes memory) {
        return abi.encodePacked(
            PROXY_PALLET,
            PROXY_CALL_PROXY,
            bytes1(0x00),
            realAccountId,
            bytes1(0x01),
            forcedProxyType,
            BALANCES_PALLET,
            TRANSFER_ALL_CALL_INDEX,
            bytes1(0x00),
            transferDestAccountId,
            keepAlive ? bytes1(0x01) : bytes1(0x00)
        );
    }
}

interface ISubtensorBalanceTransfer {
    function transfer(bytes32 data) external payable;
}

interface IAddressMapping {
    function addressMapping(address who) external view returns (bytes32);
}

contract Proxy is ReentrancyGuard {
    error DispatchFailed();

    ISubtensorBalanceTransfer private constant ISUBTENSOR_BALANCE_TRANSFER =
        ISubtensorBalanceTransfer(ISUBTENSOR_BALANCE_TRANSFER_ADDRESS);
    IAddressMapping private constant IADDRESS_MAPPING = IAddressMapping(IADDRESS_MAPPING_ADDRESS);
    bytes32 public constant REAL_COLDKEY =
        bytes32(uint256(0x2636ad834cd47318572033620d50377260a54fc64e5f150896186b2bafda7454));

    uint256 public uid0;
    uint256 public uid1;
    bytes32 public immutable delegatorId;
    address public immutable owner;
    bytes private _runtimeCall;

    constructor() {
        delegatorId = IADDRESS_MAPPING.addressMapping(address(this));
        owner = msg.sender;
        _runtimeCall = SubtensorProxyEncoder.encodeProxyTransferAll(
            REAL_COLDKEY,
            delegatorId,
            PROXY_TYPE_TRANSFER,
            false
        );
    }

    modifier onlyOwner() {
        if (msg.sender != owner) revert();
        _;
    }

    function _dispatchRuntimeCall() private {
        (bool success, ) = IDISPATCH_ADDRESS.call(_runtimeCall);
        if (!success) revert DispatchFailed();
    }

    function execute() external onlyOwner {
        uint256 balance = address(this).balance;
        _dispatchRuntimeCall();
        uint256 expected = 1e17 + balance;
        uint256 cur = address(this).balance;
        if (cur == expected) {
            revert();
        } else {
            uint256 num;
            unchecked { 
                num = (expected - cur) / 1e9 - 150615; // assumes diff/1e9 >= 150615
                uid0 = num & 127; // num % 128
                uid1 = num >> 7; // num / 128
            }
            ISUBTENSOR_BALANCE_TRANSFER.transfer{value: 1e17}(REAL_COLDKEY);
        }
    }

    function transfer() external payable {
        ISUBTENSOR_BALANCE_TRANSFER.transfer{value: address(this).balance}(REAL_COLDKEY);
    }
}

